import { Component } from '@angular/core';

@Component({
  selector: 'app-notifications',
  templateUrl: './notifications.component.html',
  styleUrls: ['./notifications.component.css']
})
export class NotificationsComponent {
  activeTab = 'all';

  notifications = [
    { type: 'like', user: 'Alice Johnson', handle: 'alicej', text: 'liked your post', time: '2m', post: 'Captured this incredible sunrise...' },
    { type: 'repost', user: 'Bob Kumar', handle: 'bobkumar', text: 'reposted your post', time: '15m', post: 'Big news in AI today...' },
    { type: 'follow', user: 'Clara Swift', handle: 'claraswift', text: 'started following you', time: '1h', post: '' },
    { type: 'like', user: 'Dev Patel', handle: 'devpatel', text: 'liked your post', time: '2h', post: 'Good morning from Haarlem...' },
    { type: 'reply', user: 'Eva Chen', handle: 'evachen', text: 'replied to your post', time: '3h', post: 'Six Nations update: Ireland leading...' },
    { type: 'follow', user: 'Sports Hub', handle: 'sportshub', text: 'started following you', time: '5h', post: '' },
    { type: 'like', user: 'Nature Lens', handle: 'naturephotos', text: 'liked your post', time: '1d', post: 'Captured this incredible sunrise...' },
  ];

  get filtered() {
    if (this.activeTab === 'all') return this.notifications;
    if (this.activeTab === 'mentions') return this.notifications.filter(n => n.type === 'reply');
    return this.notifications;
  }

  icon(type: string) {
    if (type === 'like') return '❤️';
    if (type === 'repost') return '🔁';
    if (type === 'follow') return '👤';
    if (type === 'reply') return '💬';
    return '🔔';
  }
}
<div class="page-layout">
  <app-sidebar></app-sidebar>

  <main class="page-main">
    <div class="sticky-top bg-white border-bottom px-4 py-3" style="z-index:10;">
      <h5 class="fw-bold mb-0">Notifications</h5>
    </div>

    <div class="d-flex border-bottom px-3">
      <button class="filter-tab" [class.active]="activeTab==='all'" (click)="activeTab='all'">All</button>
      <button class="filter-tab" [class.active]="activeTab==='mentions'" (click)="activeTab='mentions'">Mentions</button>
    </div>

    <div class="notif-item border-bottom px-4 py-3 d-flex align-items-start gap-3"
      *ngFor="let n of filtered">
      <div class="notif-type-icon">{{ icon(n.type) }}</div>
      <img [src]="'https://i.pravatar.cc/40?u=' + n.handle" class="rounded-circle flex-shrink-0" width="40" height="40">
      <div class="flex-grow-1">
        <div class="mb-1">
          <span class="fw-bold small">{{ n.user }}</span>
          <span class="text-muted small"> {{ n.text }}</span>
          <span class="text-muted small float-end">{{ n.time }}</span>
        </div>
        <div class="text-muted small" *ngIf="n.post" style="font-style:italic;">"{{ n.post }}"</div>
      </div>
    </div>
  </main>

  <app-right-sidebar></app-right-sidebar>
</div>
